// ─── PREDICTOR ────────────────────────────────────────────────────────────────
let predComm='OC', prefEngg=false, prefArts=false, prefNirf=false, prefNaac=false, prefSeats30=false;
let resFilter='all';
let predResults=[];

function syncSlider(){const v=parseFloat(document.getElementById('predMark').value)||0;document.getElementById('predSlider').value=v;}
function syncMark(){const v=document.getElementById('predSlider').value;document.getElementById('predMark').value=v;}
function selComm(c){
  predComm=c;
  document.querySelectorAll('.cs-btn').forEach(b=>b.classList.toggle('sel',b.dataset.c===c));
}
function togglePref(p){
  if(p==='engg'){prefEngg=!prefEngg;document.getElementById('pref-engg').classList.toggle('on',prefEngg);}
  if(p==='arts'){prefArts=!prefArts;document.getElementById('pref-arts').classList.toggle('on',prefArts);}
  if(p==='nirf'){prefNirf=!prefNirf;document.getElementById('pref-nirf').classList.toggle('on',prefNirf);}
  if(p==='naac'){prefNaac=!prefNaac;document.getElementById('pref-naac').classList.toggle('on',prefNaac);}
  if(p==='seats30'){prefSeats30=!prefSeats30;document.getElementById('pref-seats30').classList.toggle('on',prefSeats30);}
}
function setResFilter(f,btn){
  resFilter=f;
  document.querySelectorAll('.rf-btn').forEach(b=>b.classList.remove('on'));
  btn.classList.add('on');
  renderResults();
}
function chanceOf(mark,cutoff){
  const diff=mark-cutoff;
  if(diff>=5) return 'safe';
  if(diff>=1) return 'moderate';
  if(diff>=0) return 'borderline';
  if(diff>=-2) return 'risky';
  return null; // not qualified
}

function runPredictor(){
  const mark=parseFloat(document.getElementById('predMark').value);
  if(isNaN(mark)||mark<0||mark>100){alert('Please enter a valid TANCET score between 0 and 100');return;}

  // Filter colleges
  let candidates=DATA.filter(r=>{
    const cutoff=r[predComm];
    if(cutoff===null||cutoff===undefined) return false;
    const diff=mark-cutoff;
    if(diff<-2) return false; // too far below
    if(prefEngg&&r.category!=='Engineering') return false;
    if(prefArts&&r.category!=='Arts & Science') return false;
    if(prefNirf&&!r.nirf_rank) return false;
    if(prefNaac&&!r.naac_grade) return false;
    if(prefSeats30&&r.seats<30) return false;
    return true;
  });

  // Enrich with chance
  predResults=candidates.map(r=>{
    const cutoff=r[predComm];
    const diff=+(mark-cutoff).toFixed(3);
    const chance=chanceOf(mark,cutoff);
    return {...r,cutoff,diff,chance};
  }).sort((a,b)=>{
    // Sort: safe first, then by diff desc (closest to cutoff at top of risky)
    const order={safe:0,moderate:1,borderline:2,risky:3};
    if(order[a.chance]!==order[b.chance]) return order[a.chance]-order[b.chance];
    return b.cutoff-a.cutoff; // within same category, higher cutoff first
  });

  // Update summary
  const safe=predResults.filter(r=>r.chance==='safe').length;
  const mod=predResults.filter(r=>r.chance==='moderate').length;
  const bline=predResults.filter(r=>r.chance==='borderline').length;
  const risky=predResults.filter(r=>r.chance==='risky').length;

  document.getElementById('psMark').textContent=mark.toFixed(3);
  document.getElementById('psDetail').textContent=`Community: ${predComm} · ${candidates.length} colleges found`;
  document.getElementById('psCount').innerHTML=`<b style="color:var(--safe)">${safe} Safe</b> · <b style="color:var(--mod)">${mod} Moderate</b> · <b style="color:var(--gold)">${bline} Borderline</b> · <b style="color:var(--risk)">${risky} Risky</b>`;
  document.getElementById('predSummary').style.display='block';
  document.getElementById('resTitle').textContent=`${candidates.length} Colleges Found for Score ${mark} (${predComm})`;
  document.getElementById('resSub').textContent=`Showing colleges where your mark is within +5 to −2 of the ${predComm} cutoff`;

  resFilter='all';
  document.querySelectorAll('.rf-btn').forEach(b=>b.classList.remove('on'));
  document.getElementById('rfAll').classList.add('on');
  renderResults();
}

function renderResults(){
  const empty=document.getElementById('predEmpty');
  const list=document.getElementById('resList');
  if(!predResults.length){empty.style.display='block';list.style.display='none';return;}
  const filtered=resFilter==='all'?predResults:predResults.filter(r=>r.chance===resFilter);
  empty.style.display='none';
  list.style.display='flex';
  list.innerHTML=filtered.map((r,i)=>{
    const chCls=r.chance;
    const chLabel={safe:'✅ Safe',moderate:'🟡 Moderate',borderline:'⚠ Borderline',risky:'🔴 Risky'}[r.chance]||'?';
    const tierCls={'Tier 1 - Elite':'pill-tier1','Tier 2 - Premier':'pill-tier2','Tier 3 - Good':'pill-tier3','Tier 4 - Standard':'pill-tier4','Tier 5 - Open':'pill-tier5'};
    return `<div class="res-card ${chCls}">
      <div class="rc-rank">${i+1}</div>
      <div class="rc-body">
        <div class="rc-name">${r.name}</div>
        <div class="rc-meta">
          <span>Code: <b>${r.code}</b></span>
          <span>${r.branch}</span>
          <span>${r.seats} seats</span>
          ${r.nirf_rank?`<span style="color:var(--gold)">NIRF #${r.nirf_rank}</span>`:''}
        </div>
        <div class="rc-pills">
          <span class="pill ${r.category==='Engineering'?'pill-cat-engg':'pill-cat-arts'}">${r.category==='Engineering'?'⚙ Engg':'🎨 Arts'}</span>
          <span class="pill ${tierCls[r.tier]||'pill-tier5'}">${TIER_LABELS[r.tier]||r.tier}</span>
          ${r.nirf_rank?`<a href="${NIRF_URL}" target="_blank" class="pill pill-nirf">🏅 NIRF #${r.nirf_rank}</a>`:''}
          ${r.naac_grade?`<a href="${NAAC_URL}" target="_blank" class="pill pill-naac">✅ NAAC ${r.naac_grade}</a>`:''}
          ${r.comm_count===7?'<span class="pill" style="background:#e8f0fe;color:#1a4fa0">🌍 All 7 comms</span>':''}
        </div>
      </div>
      <div class="rc-right">
        <div class="rc-cutoff ${chCls}">${r.cutoff.toFixed(3)}</div>
        <div class="rc-margin">${r.diff>=0?'+':''}${r.diff.toFixed(3)} margin</div>
        <div><span class="rc-chance chance-${chCls}">${chLabel}</span></div>
      </div>
    </div>`;
  }).join('');
  if(!filtered.length) list.innerHTML='<div class="no-res">No colleges match this filter.</div>';
}

// ─── FULL TABLE ────────────────────────────────────────────────────────────────
let tblCat='all',tblNirf=false,tblNaac=false,tblT1=false;
function setTblCat(c,btn){tblCat=c;['tf-all','tf-engg','tf-arts'].forEach(id=>document.getElementById(id).classList.remove('on'));btn.classList.add('on');renderTable();}
function toggleTblFlag(f,btn){
  if(f==='nirf'){tblNirf=!tblNirf;btn.classList.toggle('on',tblNirf);}
  if(f==='naac'){tblNaac=!tblNaac;btn.classList.toggle('on',tblNaac);}
  if(f==='t1'){tblT1=!tblT1;btn.classList.toggle('on',tblT1);}
  renderTable();
}
function renderTable(){
  const q=document.getElementById('tblSearch').value.toLowerCase();
  const sort=document.getElementById('tblSort').value;
  let d=DATA.filter(r=>{
    if(q&&!r.name.toLowerCase().includes(q)&&!String(r.code).includes(q)&&!r.branch.toLowerCase().includes(q))return false;
    if(tblCat!=='all'&&r.category!==tblCat)return false;
    if(tblNirf&&!r.nirf_rank)return false;
    if(tblNaac&&!r.naac_grade)return false;
    if(tblT1&&!(r.OC&&r.OC>=90))return false;
    return true;
  });
  if(sort==='oc_desc') d.sort((a,b)=>(b.OC??-1)-(a.OC??-1));
  else if(sort==='oc_asc') d.sort((a,b)=>(a.OC??9999)-(b.OC??9999));
  else if(sort==='nirf_asc') d.sort((a,b)=>(a.nirf_rank??9999)-(b.nirf_rank??9999));
  else if(sort==='seats_desc') d.sort((a,b)=>b.seats-a.seats);
  else if(sort==='comm_desc') d.sort((a,b)=>b.comm_count-a.comm_count);
  else if(sort==='avg_desc') d.sort((a,b)=>{if(a.avg_valid&&b.avg_valid)return b.avg_cutoff-a.avg_cutoff;if(a.avg_valid)return -1;if(b.avg_valid)return 1;return(b.OC??-1)-(a.OC??-1);});
  else if(sort==='code_asc') d.sort((a,b)=>String(a.code).localeCompare(String(b.code),undefined,{numeric:true}));

  const tbody=document.getElementById('tblBody');
  const noRes=document.getElementById('tblNoRes');
  document.getElementById('tblCount').textContent=`Showing ${d.length} of 242 colleges`;
  if(!d.length){tbody.innerHTML='';noRes.style.display='block';return;}
  noRes.style.display='none';

  const mc=v=>v===null?'<span class="dash-cell">—</span>':`<span class="${v>=90?'m-high':v>=60?'m-mid':v>=30?'m-low':'m-vlo'}">${v.toFixed(3)}</span>`;
  const tierCls={'Tier 1 - Elite':'tier1','Tier 2 - Premier':'tier2','Tier 3 - Good':'tier3','Tier 4 - Standard':'tier4','Tier 5 - Open':'tier5'};
  const naacFg={'A++':'#14784a','A+':'#1565c0','A':'#c0392b'};

  tbody.innerHTML=d.map(r=>`<tr>
    <td class="td-code">${r.code}</td>
    <td class="td-name td-l">${r.name}<small>${r.branch}</small></td>
    <td class="td-c"><span style="font-size:10px;font-weight:700;color:${r.category==='Engineering'?'#1a4fa0':'#7b2d8b'}">${r.category==='Engineering'?'Engg':'Arts'}</span></td>
    ${COMMS.map(c=>`<td class="td-c">${mc(r[c])}</td>`).join('')}
    <td class="td-c" style="font-weight:700;background:#fffbec">${r.seats}</td>
    <td class="td-c"><span style="font-size:10px;font-weight:700;color:${TIER_COLORS[r.tier]||'#666'}">${TIER_LABELS[r.tier]||r.tier}</span></td>
    <td class="td-c">${r.avg_valid&&r.avg_cutoff?`<span style="font-weight:800;color:#5c2d91">${r.avg_cutoff}</span>`:'<span style="color:#ccc;font-size:10px">N/A</span>'}</td>
    <td class="td-c" style="font-weight:700;color:${r.comm_count===7?'#14784a':r.comm_count>=4?'#1a4fa0':'#888'}">${r.comm_count}/7</td>
    <td class="td-c">${r.nirf_rank?`<a href="${NIRF_URL}" target="_blank" style="font-weight:800;color:#b8860b;text-decoration:none">#${r.nirf_rank}</a>`:'<span style="color:#ddd">—</span>'}</td>
    <td class="td-c">${r.naac_grade?`<a href="${NAAC_URL}" target="_blank" style="font-weight:800;color:${naacFg[r.naac_grade]||'#333'};text-decoration:none">${r.naac_grade}</a>`:'<span style="color:#ddd">—</span>'}</td>
  </tr>`).join('');
}

function exportCSV(){
  const q=document.getElementById('tblSearch').value.toLowerCase();
  let d=DATA.filter(r=>{
    if(q&&!r.name.toLowerCase().includes(q)&&!String(r.code).includes(q))return false;
    if(tblCat!=='all'&&r.category!==tblCat)return false;
    return true;
  });
  const h=['Code','College Name','Category','Branch','OC','BC','BCM','MBC','SC','SCA','ST','Seats','Tier','Avg(Valid)','Comms','NIRF','NAAC'].join(',');
  const rows=d.map(r=>[r.code,`"${r.name}"`,r.category,r.branch,...COMMS.map(c=>r[c]??''),r.seats,r.tier,r.avg_valid&&r.avg_cutoff?r.avg_cutoff:'',r.comm_count,r.nirf_rank??'',r.naac_grade??''].join(','));
  const a=document.createElement('a');
  a.href='data:text/csv;charset=utf-8,\uFEFF'+encodeURIComponent([h,...rows].join('\n'));
  a.download='MBA_TANCET_2025.csv'; a.click();
}

